```python
class Solution:
    def findSubstring(self, s: str, words: List[str]) -> List[int]:
        if not s or not words or not words[0]:
            return []

        wlen = len(words[0])
        slen = wlen * len(words)
        occ = collections.Counter(words)
        res = []

        for k in range(wlen):
            track = dict()
            # Initialize track with all words set to 0
            for word in words:
                if word not in track:
                    track[word] = 0

            # Sliding window approach
            for i in range(k, len(s) - wlen + 1, wlen):
                w = s[i:i+wlen]

                if w in occ:
                    track[w] = track.get(w, 0) + 1

                    # If we have more occurrences than needed, shrink window from left
                    if i >= slen:
                        left_word = s[i - slen:i - slen + wlen]
                        track[left_word] -= 1
                        if track[left_word] == 0:
                            del track[left_word]

                    # Check if current window is valid (contains all words with correct counts)
                    if i >= slen - wlen and self.isValid(track, occ):
                        res.append(i - slen + wlen)
                else:
                    # Reset the window since we hit a word not in our list
                    track.clear()

        return res

    def isValid(self, track: dict, occ: dict) -> bool:
        if len(track) != len(occ):
            return False

        for key, val in track.items():
            if val != occ.get(key, 0):
                return False
        return True
